import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Table, TableBody, TableCell, TableHead, TableRow, Button, TextField, Box } from '@material-ui/core';

export default function CategoryManagement() {
  const [categories, setCategories] = useState([]);
  const [newCategory, setNewCategory] = useState({ name: '' });

  useEffect(() => {
    axios.get('http://localhost:8080/api/categories').then(res => setCategories(res.data));
  }, []);

  const addCategory = () => {
    axios.post('http://localhost:8080/api/categories', newCategory).then(res => {
      setCategories([...categories, res.data]);
      setNewCategory({ name: '' });
    });
  };

  return (
    <div>
      <Box marginBottom={2}>
        <TextField
          label="Category Name"
          value={newCategory.name}
          onChange={e => setNewCategory({ ...newCategory, name: e.target.value })}
        />
        <Button onClick={addCategory} color="primary" variant="contained">Add Category</Button>
      </Box>
      <Table>
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {categories.map(category => (
            <TableRow key={category.id}>
              <TableCell>{category.name}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  );
}
